package cmd

import (
	"context"
	"fmt"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/DocumentDrivenDX/ddx/internal/metaprompt"
	"github.com/DocumentDrivenDX/ddx/internal/metric"
	"github.com/DocumentDrivenDX/ddx/internal/persona"
	"github.com/DocumentDrivenDX/ddx/internal/registry"
	"github.com/DocumentDrivenDX/ddx/internal/update"
	"github.com/fatih/color"
	"github.com/mattn/go-isatty"
	"github.com/spf13/cobra"
	"github.com/spf13/viper"
)

const versionTemplate = `DDx {{.Version}}
Commit: {{index .Annotations "commit"}}
Built: {{index .Annotations "date"}}
`

// CommandFactory creates fresh command instances without global state
type CommandFactory struct {
	// Configuration options
	Version string
	Commit  string
	Date    string

	// Working directory (injected once at startup)
	WorkingDir string

	// AgentRunnerOverride overrides the agent runner used by the
	// execute-bead path (legacy agent.AgentRunner interface). For testing.
	AgentRunnerOverride agent.AgentRunner

	// ExecAgentRunnerOverride overrides the agent runner used by execStore.
	// SD-024 Stage 2: distinct from AgentRunnerOverride because the exec
	// AgentRunner interface has migrated to (ctx, ResolvedConfig, runtime),
	// while agent.AgentRunner still uses the legacy RunArgs signature.
	// For testing.
	ExecAgentRunnerOverride ddxexec.AgentRunner

	// executeBeadGitOverride overrides git operations in execute-bead worker (for testing).
	executeBeadGitOverride agent.GitOps

	// executeBeadOrchestratorGitOverride overrides git operations in the
	// execute-bead orchestrator (LandBeadResult) for testing.
	executeBeadOrchestratorGitOverride agent.OrchestratorGitOps

	// executeBeadLandingGitOverride overrides the LandingGitOps used by the
	// single-bead CLI and the execute-loop LandCoordinator for testing.
	executeBeadLandingGitOverride agent.LandingGitOps

	// executeBeadLandingAdvancerOverride, when non-nil, replaces the default
	// Land() wrapper used by the interactive single-bead CLI with a custom
	// callback. Tests inject this to assert on the number of land calls
	// without needing a real git repo.
	executeBeadLandingAdvancerOverride func(res *agent.ExecuteBeadResult) (*agent.LandResult, error)

	// syncGitRunnerOverride replaces the real git runner in 'ddx sync' (for testing).
	syncGitRunnerOverride syncGitRunner

	// tryExecutorOverride, when non-nil, replaces the real executor used by
	// "ddx try". Injected by tests to observe claim/execute/outcome without
	// shelling out to a real agent harness.
	tryExecutorOverride agent.ExecuteBeadExecutor

	// resourceCheckerOverride, when non-nil, replaces the default execution
	// resource preflight used by ddx try and ddx work.
	resourceCheckerOverride agent.ExecutionResourceChecker

	// Custom viper instance for isolation
	viperInstance *viper.Viper

	// Update checker instance (stores check result for PostRunE)
	updateChecker *update.Checker
	updateDone    chan struct{}
	updateMu      sync.Mutex
}

// NewCommandFactory creates a new command factory with default settings
func NewCommandFactory(workingDir string) *CommandFactory {
	return &CommandFactory{
		Version:       Version,
		Commit:        Commit,
		Date:          Date,
		WorkingDir:    workingDir,
		viperInstance: viper.New(),
	}
}

// NewRootCommand creates a fresh root command with all subcommands
func (f *CommandFactory) NewRootCommand() *cobra.Command {
	// Local flag variables scoped to this command instance
	var cfgFile string
	var verbose bool
	var libraryPath string

	// Create fresh root command
	rootCmd := &cobra.Command{
		Use:   "ddx",
		Short: "Document-Driven Development eXperience - AI development toolkit",
		Long: color.New(color.FgCyan).Sprint(banner) + `
DDx is a toolkit for AI-assisted development that helps you:

• Share templates, prompts, and patterns across projects
• Maintain consistent development practices
• Integrate AI tooling seamlessly
• Contribute improvements back to the community

Get started:
  ddx init          Initialize DDx in your project
  ddx list          See available resources
  ddx doctor        Check installation and diagnose issues

More information:
  Documentation: https://github.com/DocumentDrivenDX/ddx
  Issues & Support: https://github.com/DocumentDrivenDX/ddx/issues`,
		PersistentPreRun: func(cmd *cobra.Command, args []string) {
			if verbose {
				fmt.Printf("DDx %s (commit: %s, built: %s)\n", f.Version, f.Commit, f.Date)
			}
		},
	}

	rootCmd.Version = formattedVersion(f.Version)
	rootCmd.Annotations = map[string]string{
		"commit": f.Commit,
		"date":   f.Date,
	}
	rootCmd.SetVersionTemplate(versionTemplate)

	// Setup flags - these are now local to this command instance
	rootCmd.PersistentFlags().StringVar(&cfgFile, "config", "", "config file (default is $HOME/.ddx.yml)")
	rootCmd.PersistentFlags().BoolVarP(&verbose, "verbose", "v", false, "verbose output")
	rootCmd.PersistentFlags().StringVar(&libraryPath, "library-base-path", "", "override path for DDx library location")

	// Store flag values in command context for access by subcommands
	rootCmd.PersistentPreRunE = func(cmd *cobra.Command, args []string) error {
		// Initialize config with the local viper instance
		f.initConfig(cfgFile, libraryPath)

		// Version gate: block old binary from running in newer project
		if err := f.checkVersionGate(cmd); err != nil {
			return err
		}

		// Check for updates (synchronous, once per 24h)
		f.checkForUpdates(cmd)

		// Call the original PersistentPreRun if it exists
		if rootCmd.PersistentPreRun != nil {
			rootCmd.PersistentPreRun(cmd, args)
		}
		return nil
	}

	// Display update notification and staleness hints after command completes
	rootCmd.PersistentPostRunE = func(cmd *cobra.Command, args []string) error {
		if err := f.displayUpdateNotification(cmd); err != nil {
			return err
		}
		f.displayStalenessHints(cmd)
		return nil
	}

	// Add all subcommands
	f.registerSubcommands(rootCmd)

	// Keep the persona APIs in the static production graph. Cobra dispatch
	// does not always show up in deadcode RTA, so this explicit hook keeps the
	// real CLI implementations visible without changing runtime behavior.
	persona.KeepReachabilityForDeadcode()
	metaprompt.KeepReachabilityForDeadcode()
	metric.KeepReachabilityForDeadcode()

	return rootCmd
}

func formattedVersion(version string) string {
	if version == "dev" {
		return "v0.0.1-dev"
	}
	if !strings.HasPrefix(version, "v") {
		return "v" + version
	}
	return version
}

func (f *CommandFactory) versionOutput() string {
	return fmt.Sprintf("DDx %s\nCommit: %s\nBuilt: %s\n", formattedVersion(f.Version), f.Commit, f.Date)
}

// initConfig initializes configuration for this command instance
func (f *CommandFactory) initConfig(cfgFile, libPath string) {
	// Store library path override if provided
	if libPath != "" {
		_ = os.Setenv("DDX_LIBRARY_BASE_PATH", libPath)
	}

	if cfgFile != "" {
		// Use config file from the flag
		f.viperInstance.SetConfigFile(cfgFile)
	} else {
		// Find home directory
		home, err := os.UserHomeDir()
		if err == nil {
			// Search for config in home directory with name ".ddx" (without extension)
			f.viperInstance.AddConfigPath(home)
			f.viperInstance.AddConfigPath(".")
			f.viperInstance.SetConfigType("yaml")
			f.viperInstance.SetConfigName(".ddx")
		}
	}

	f.viperInstance.AutomaticEnv() // read in environment variables that match

	// If a config file is found, read it in
	if err := f.viperInstance.ReadInConfig(); err == nil {
		if verbose := f.viperInstance.GetBool("verbose"); verbose {
			_, _ = fmt.Fprintln(os.Stderr, "Using config file:", f.viperInstance.ConfigFileUsed())
		}
	}
}

// checkForUpdates performs automatic update check (synchronous, once per 24h)
func (f *CommandFactory) checkForUpdates(cmd *cobra.Command) {
	// Check if disabled via env var
	if os.Getenv("DDX_DISABLE_UPDATE_CHECK") == "1" {
		return
	}

package cmd

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"runtime"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/DocumentDrivenDX/ddx/internal/metaprompt"
	"github.com/DocumentDrivenDX/ddx/internal/registry"
	"github.com/spf13/cobra"
)

// DiagnosticIssue represents a detected problem and its remediation
type DiagnosticIssue struct {
	Type        string
	Description string
	Remediation []string
	SystemInfo  map[string]string
}

// runDoctor implements the doctor command logic
func (f *CommandFactory) runDoctor(cmd *cobra.Command, args []string) error {
	verbose, _ := cmd.Flags().GetBool("verbose")
	fix, _ := cmd.Flags().GetBool("fix")

	fmt.Println("🩺 DDx Installation Diagnostics")
	fmt.Println("=====================================")
	fmt.Println()

	var issues []DiagnosticIssue
	allGood := true
	auditPlugins, _ := cmd.Flags().GetBool("plugins")

	// Check 1: DDX Binary Executable and Install Location
	fmt.Print("✓ Checking DDX Binary... ")
	executable, err := os.Executable()
	if err != nil {
		fmt.Println("❌ Cannot determine executable location")
		allGood = false
	} else {
		fmt.Printf("✅ DDX Binary Executable (%s)\n", executable)
		if locationIssues := checkBinaryInstallLocation(executable); len(locationIssues) > 0 {
			for _, issue := range locationIssues {
				fmt.Printf("   ⚠️  %s\n", issue.Description)
				for _, r := range issue.Remediation {
					fmt.Printf("   💡 %s\n", r)
				}
			}
			issues = append(issues, locationIssues...)
		}
	}

	// Check 2: PATH Configuration
	fmt.Print("✓ Checking PATH Configuration... ")
	if isInPath() {
		fmt.Println("✅ PATH Configuration")
	} else {
		fmt.Println("⚠️  DDX not found in PATH")

		// Check for problem simulation
		problemState := os.Getenv("DDX_PROBLEM_STATE")
		if problemState == "path_issue" || verbose {
			issues = append(issues, DiagnosticIssue{
				Type:        "path_configuration",
				Description: "DDX binary not accessible from PATH",
				Remediation: []string{
					"Run 'ddx setup path'",
					"Restart shell session",
					"Manually add to PATH",
				},
				SystemInfo: map[string]string{
					"shell": os.Getenv("SHELL"),
					"path":  os.Getenv("PATH"),
				},
			})
		}

		if !verbose {
			suggestPathFix()
		}
		// Not marking as failure since DDx is running
	}

	// Check 3: Configuration File
	fmt.Print("✓ Checking Configuration... ")
	if checkConfiguration() {
		fmt.Println("✅ Configuration Valid")
	} else {
		fmt.Println("⚠️  Configuration Issues (non-critical)")
	}

	// Check 4: Git Installation
	fmt.Print("✓ Checking Git... ")
	if checkGit() {
		fmt.Println("✅ Git Available")
	} else {
		fmt.Println("❌ Git Not Found")
		fmt.Println("   Git is required for DDX synchronization features")
		allGood = false
	}

	// Check 4b: Git Repo Health (core.bare / core.worktree corruption)
	fmt.Print("✓ Checking Git Repo Health... ")
	repoIssues := checkGitRepoHealth(f.WorkingDir, fix)
	if len(repoIssues) == 0 {
		fmt.Println("✅ Git Repo Clean")
	} else {
		if fix {
			fmt.Printf("🔧 Git Repo Issues Fixed (%d)\n", len(repoIssues))
		} else {
			fmt.Printf("⚠️  Git Repo Issues (%d) — re-run with --fix to remediate\n", len(repoIssues))
		}
		for _, issue := range repoIssues {
			fmt.Printf("   ⚠️  %s\n", issue.Description)
			for _, r := range issue.Remediation {
				fmt.Printf("   💡 %s\n", r)
			}
		}
		issues = append(issues, repoIssues...)
	}

	// Check 5: Network Connectivity
	fmt.Print("✓ Checking Network... ")
	if checkNetwork() {
		fmt.Println("✅ Network Connectivity")
	} else {
		fmt.Println("⚠️  Network Issues (optional)")

		// Check for problem simulation
		problemState := os.Getenv("DDX_PROBLEM_STATE")
		if problemState == "network_issue" || verbose {
			issues = append(issues, DiagnosticIssue{
				Type:        "network_connectivity",
				Description: "Unable to reach external repositories",
				Remediation: []string{
					"Check internet connection",
					"Verify proxy settings",
					"Try offline installation",
				},
				SystemInfo: map[string]string{
					"dns_server": "Check /etc/resolv.conf or network settings",
					"proxy":      os.Getenv("HTTP_PROXY"),
				},
			})
		}
	}

	// Check 7: Permissions
	fmt.Print("✓ Checking Permissions... ")
	problemState := os.Getenv("DDX_PROBLEM_STATE")
	if checkPermissions() && problemState != "permission_issue" {
		fmt.Println("✅ File Permissions")
	} else {
		fmt.Println("❌ Permission Issues")
		allGood = false

		// Add permission issue details for critical failures or verbose mode
		if problemState == "permission_issue" || verbose || !checkPermissions() {
			issues = append(issues, DiagnosticIssue{
				Type:        "file_permissions",
				Description: "Cannot create files in current directory",
				Remediation: []string{
					"Check directory permissions",
					"Try installing to different location",
					"Verify user has write access",
				},
				SystemInfo: map[string]string{
					"user":        os.Getenv("USER"),
					"working_dir": f.WorkingDir,
					"permissions": getDirectoryPermissions(f.WorkingDir),
				},
			})
		}
	}

	// Check 8: Library Path
	fmt.Print("✓ Checking Library Path... ")
	if checkLibraryPathFromWorkingDir(f.WorkingDir) {
		fmt.Println("✅ Library Path Accessible")
	} else {
		fmt.Println("⚠️  Library Path Issues (optional)")

		// Check for problem simulation
		problemState := os.Getenv("DDX_PROBLEM_STATE")
		if problemState == "library_path_issue" || verbose {
			issues = append(issues, DiagnosticIssue{
				Type:        "library_path_configuration",
				Description: "DDX library path not accessible or not configured",
				Remediation: []string{
					"Initialize DDX in your project with 'ddx init'",
					"Check .ddx.yml configuration file",
					"Verify library path exists and is readable",
					"Try setting DDX_LIBRARY_BASE_PATH environment variable",
					"Re-clone or update DDX library repository",
				},
				SystemInfo: map[string]string{
					"library_path": getLibraryPathInfo(f.WorkingDir),
					"config_file":  getConfigFileInfo(),
					"env_override": os.Getenv("DDX_LIBRARY_BASE_PATH"),
				},
			})
		}
	}

	// Check 9: Meta-Prompt Sync Status
	fmt.Print("✓ Checking Meta-Prompt Sync... ")
	if metaPromptCheck := checkMetaPromptSync(f.WorkingDir); metaPromptCheck == nil {
		fmt.Println("✅ Meta-Prompt In Sync")
	} else {
		fmt.Println("⚠️  Meta-Prompt Out of Sync")
		if verbose {
			issues = append(issues, DiagnosticIssue{
				Type:        "meta_prompt_sync",
				Description: metaPromptCheck.Error(),
				Remediation: []string{
					"Run 'ddx update' to sync meta-prompt",
				},
				SystemInfo: map[string]string{
					"claude_file": filepath.Join(f.WorkingDir, "CLAUDE.md"),
				},
			})
		}
	}

	// Check 10: Installed Package Launchers
	checkInstalledLaunchers(verbose)

	if auditPlugins {
		pluginIssues := checkInstalledPlugins(verbose)
		if len(pluginIssues) > 0 {
			allGood = false
			issues = append(issues, pluginIssues...)
		}
	}

	// Check 11: Sync failure marker — surfaces aborted 'ddx sync' runs.
	fmt.Print("✓ Checking Sync Status... ")
	syncFailurePath := filepath.Join(f.WorkingDir, ".ddx", "sync-failure.json")
	if ws := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); ws != "" {
		syncFailurePath = filepath.Join(ws, ".ddx", "sync-failure.json")
	}
	if syncIssue := checkSyncFailure(syncFailurePath); syncIssue != nil {
		fmt.Println("⚠️  Sync aborted")
		fmt.Printf("   ⚠️  %s\n", syncIssue.Description)
		for _, r := range syncIssue.Remediation {
			fmt.Printf("   💡 %s\n", r)
		}
		issues = append(issues, *syncIssue)
	} else {
		fmt.Println("✅ Sync Status")
	}

package agent

import (
	"bytes"
	"context"
	"crypto/rand"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"encoding/xml"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// ExecuteBeadResult captures the outcome of an execute-bead worker run.
// The worker populates the task-level fields (BeadID through UsageFile).
// The parent orchestrator (LandBeadResult) populates the landing fields
// (Outcome, Status, Detail, Reason, PreserveRef, GateResults, RequiredExecSummary,
// ChecksFile) via ApplyLandingToResult before the result is written to disk or
// returned to a caller.
type ExecuteBeadResult struct {
	BeadID    string `json:"bead_id"`
	AttemptID string `json:"attempt_id,omitempty"`
	WorkerID  string `json:"worker_id,omitempty"`
	BaseRev   string `json:"base_rev"`
	ResultRev string `json:"result_rev,omitempty"`

	// Outcome and Status are initially set by the worker to task-level values
	// (task_succeeded / task_failed / task_no_changes), then overwritten by
	// ApplyLandingToResult with the landing decision (merged / preserved /
	// no-changes) so callers see a unified record.
	Outcome string `json:"outcome"`
	Status  string `json:"status,omitempty"`
	Detail  string `json:"detail,omitempty"`

	// Landing fields — populated by ApplyLandingToResult, not by ExecuteBead.
	Reason              string            `json:"reason,omitempty"`
	PreserveRef         string            `json:"preserve_ref,omitempty"`
	GateResults         []GateCheckResult `json:"gate_results,omitempty"`
	RequiredExecSummary string            `json:"required_exec_summary,omitempty"`
	ChecksFile          string            `json:"checks_file,omitempty"`
	// Ratchet fields — populated by ApplyLandingToResult when declarative
	// ratchet thresholds were evaluated during landing. HELIX and other
	// consumers use these to distinguish ratchet-preserved attempts from
	// generic execution failures.
	RatchetEvidence []RatchetEvidence `json:"ratchet_evidence,omitempty"`
	RatchetSummary  string            `json:"ratchet_summary,omitempty"`

	// NoChangesRationale is populated when outcome == task_no_changes and the
	// agent wrote a rationale file to the execution bundle dir inside the
	// worktree. It carries the agent's explanation of why no commits were made.
	NoChangesRationale string `json:"no_changes_rationale,omitempty"`

	// NoEvidencePaths names worktree paths that remained dirty when the agent
	// exited without creating a commit or no_changes_rationale.txt. It helps
	// operators diagnose silent commit failures before the worktree is cleaned up.
	NoEvidencePaths []string `json:"no_evidence_paths,omitempty"`

	Harness                     string  `json:"harness,omitempty"`
	Provider                    string  `json:"provider,omitempty"`
	Model                       string  `json:"model,omitempty"`
	ActualPower                 int     `json:"actual_power,omitempty"`
	PredictedPower              int     `json:"predicted_power,omitempty"`
	PredictedSpeedTPS           float64 `json:"predicted_speed_tps,omitempty"`
	PredictedCostUSDPer1kTokens float64 `json:"predicted_cost_usd_per_1k_tokens,omitempty"`
	PredictedCostSource         string  `json:"predicted_cost_source,omitempty"`
	SessionID                   string  `json:"session_id,omitempty"`
	DurationMS                  int     `json:"duration_ms"`
	Tokens                      int     `json:"tokens,omitempty"`
	CostUSD                     float64 `json:"cost_usd,omitempty"`
	ExitCode                    int     `json:"exit_code"`
	Error                       string  `json:"error,omitempty"`

	// FailureMode classifies why an execution did not land cleanly. Empty
	// when the bead was merged (task_succeeded landing outcome). Populated
	// by the orchestrator from known patterns; see ClassifyFailureMode and
	// the FailureMode* constants in execute_bead_status.go.
	FailureMode string `json:"failure_mode,omitempty"`

	ExecutionDir    string        `json:"execution_dir,omitempty"`
	PromptFile      string        `json:"prompt_file,omitempty"`
	ManifestFile    string        `json:"manifest_file,omitempty"`
	ResultFile      string        `json:"result_file,omitempty"`
	UsageFile       string        `json:"usage_file,omitempty"`
	Stderr          string        `json:"stderr,omitempty"`
	RateLimitBudget time.Duration `json:"rate_limit_budget,omitempty"`

	StartedAt  time.Time `json:"started_at"`
	FinishedAt time.Time `json:"finished_at"`
}

// BeadEventAppender records append-only evidence events on a bead.
// Implemented by *bead.Store — kept as a minimal interface so the agent
// package does not need to import a concrete store type in tests.
type BeadEventAppender interface {
	AppendEvent(id string, event bead.BeadEvent) error
}

// BeadCancelStore reads/writes the cancel markers on a bead's Extra map.
// Implemented by *bead.Store. ADR-022 §Cancel SLA: the worker polls
// IsCancelRequested mid-attempt and on a positive read writes
// MarkCancelHonored before aborting at the next safe point.
type BeadCancelStore interface {
	IsCancelRequested(id string) (bool, error)
	MarkCancelHonored(id string) error
}

// CancelPollInterval is how often the worker checks for an operator cancel
// while an agent attempt is in flight. ADR-022 §Cancel SLA names 10s as the
// default. Exposed as a variable so tests can override it.
var CancelPollInterval = 10 * time.Second

// ExecuteBeadRuntime carries the non-durable plumbing for an execute-bead
// run: per-invocation intent (FromRev, PromptFile, WorkerID) and
// non-serializable injection seams (BeadEvents, Service, AgentRunner).
// Durable knobs (Harness, Model, Provider, ModelRef, Effort,
// ContextBudget, MirrorCfg) live on config.ResolvedConfig and are passed
// via ExecuteBeadWithConfig's rcfg argument.
//
// See SD-024 / TD-024 §Runtime structs and §Stage 3.
type ExecuteBeadRuntime struct {
	FromRev         string // base git revision (default: HEAD)
	PromptFile      string // override prompt file (auto-generated if empty)
	Output          io.Writer
	WorkerID        string // from DDX_WORKER_ID env or caller
	BeadEvents      BeadEventAppender
	BeadCancel      BeadCancelStore // optional: enables operator-cancel mid-attempt poll
	ResourceChecker ExecutionResourceChecker
	Service         agentlib.FizeauService
	AgentRunner     AgentRunner
	// RateLimitMaxWait bounds the per-bead total wait spent on rate-limit
	// retries (ddx-c6e3db02 RateLimitRetryContract / TD-031 §8.4). Zero uses
	// RateLimitRetryDefaultBudget (5 min). Negative disables the wrapper —
	// rate-limit responses fall through to the standard execution_failed path.
	RateLimitMaxWait time.Duration
}

// GitOps abstracts the git operations required by the worker.
// Merge is intentionally excluded — that belongs to the parent-side
// orchestrator (OrchestratorGitOps). UpdateRef/DeleteRef are exposed here
// so landing-side helpers (e.g. BuildLandingGateContext) can pin a
// transient ref while running gate evaluation against an ephemeral
// worktree.
type GitOps interface {
	HeadRev(dir string) (string, error)
	ResolveRev(dir, rev string) (string, error)
	WorktreeAdd(dir, wtPath, rev string) error
	WorktreeRemove(dir, wtPath string) error
	WorktreeList(dir string) ([]string, error)
	WorktreePrune(dir string) error
	IsDirty(dir string) (bool, error)
	// SynthesizeCommit stages real file changes (excluding harness noise paths) and
	// commits them using msg as the commit message. Returns (true, nil) when a
	// commit was made, (false, nil) when there was nothing real to commit (all
	// dirty files were noise), and (false, err) on failure.
	SynthesizeCommit(dir, msg string) (bool, error)
	// UpdateRef updates ref in dir to sha. Used by landing helpers to pin a
	// commit so a transient worktree can check it out without racing with
	// other work that might prune it.
	UpdateRef(dir, ref, sha string) error
	// DeleteRef removes ref from dir. Used to unpin a transient ref after
	// the consumer (e.g. an ephemeral worktree) is done with it.
	DeleteRef(dir, ref string) error
}

// AgentRunner runs an agent with the given options.
type AgentRunner interface {
	Run(opts RunArgs) (*Result, error)
